const item = $input.item.json;
const rawUrl = (item.link && item.link[0]) || (item.guid && item.guid[0]) || '';
const url = rawUrl.split('?')[0];

const id = Buffer.from(url).toString('base64').replace(/[^a-zA-Z0-9]/g, '').slice(0, 32);

const description = ((item.description && item.description[0]) || '')
  .replace(/<[^>]+>/g, '')
  .slice(0, 1500);

return {
  id,
  title: (item.title && item.title[0]) || '',
  company: (item['indeed:company'] && item['indeed:company'][0]) || '',
  location: (item['indeed:formattedLocation'] && item['indeed:formattedLocation'][0]) ||
            (item['indeed:city'] && item['indeed:city'][0]) || '',
  description,
  url,
  posted_date: (item.pubDate && item.pubDate[0]) || '',
  source: 'Indeed'
};

const POSITIVE = {
  'GKV': 20, 'gesetzliche Krankenversicherung': 20,
  'Krankenkasse': 18, 'Krankenkassen': 18,
  'BKK': 15, 'IKK': 15, 'DAK': 15, 'AOK': 15,
  'Public Sector': 15, 'öffentlicher Sektor': 15,
  'Account Manager': 15, 'Sales Manager': 15,
  'Key Account': 15, 'Business Development': 12,
  'Vertrieb': 10, 'eHealth': 15,
  'Gesundheitswesen': 12, 'Healthcare IT': 15,
  'Health IT': 15, 'IT-Consulting': 12,
  'Digital Health': 14, 'Digitalisierung': 8,
  'Ausschreibung': 15, 'Vergabe': 12,
  'BAFO': 15, 'Tender': 10,
  'KRITIS': 12, 'NIS2': 12, 'SGB V': 15,
  'Telematikinfrastruktur': 12, 'TI 2.0': 12,
  'BITMARCK': 15, 'Senior': 8,
  'Director': 5, 'Head of': 5,
  'Hamburg': 5, 'Remote': 5, 'Hybrid': 5,
  'msg': 8, 'Sopra Steria': 8,
  'Capgemini': 8, 'T-Systems': 8, 'CGI': 8,
  'Leiter Digital': 22, 'CDO': 15,
  'Chief Digital Officer': 22
};

const NEGATIVE = {
  'Zeitarbeit': -30, 'Werkstudent': -40,
  'Praktikum': -40, 'Junior': -25,
  'Pflegekraft': -40, 'Arzt': -40,
  'Medizin': -20, 'Produktion': -30,
  'Logistik': -20, 'Fahrer': -35,
  'Minijob': -40, 'Trainee': -20,
  'INIT AG': -100, 'adesso SE': -100
};

const item = $input.item.json;
if (!item.title) return null;

const text = [item.title, item.description, item.company, item.location]
  .join(' ').toLowerCase();

let score = 0;
for (const [kw, pts] of Object.entries(POSITIVE)) {
  if (text.includes(kw.toLowerCase())) score += pts;
}
for (const [kw, pen] of Object.entries(NEGATIVE)) {
  if (text.includes(kw.toLowerCase())) score += pen;
}
score = Math.max(0, Math.min(100, score));

if (score < 25) return null;

return { ...$input.item.json, keyword_score: score, score };

const seen = new Set();
const items = $input.all();
const result = [];
for (const item of items) {
  if (!item.json || !item.json.id) continue;
  if (seen.has(item.json.id)) continue;
  seen.add(item.json.id);
  result.push(item);
}
result.sort((a, b) => (b.json.score || 0) - (a.json.score || 0));
return result.slice(0, 10);

