const item = $input.item.json;
try {
  let raw = item.content[0].text.trim();
  if (raw.startsWith('```')) {
    raw = raw.split('\n').slice(1).join('\n').replace(/```$/, '').trim();
  }
  const result = JSON.parse(raw);
  const score = Math.max(0, Math.min(100, parseInt(result.score) || 0));
  const emoji = score >= 70 ? '🟢' : score >= 40 ? '🟡' : '🔵';
  return { ...item, ai_score: score, ai_reason: result.reason || '', ai_action: result.action || '', score_emoji: emoji };
} catch(e) {
  return { ...item, ai_score: item.keyword_score || 0, ai_reason: '', ai_action: '', score_emoji: '🔵' };
}
